{"content": "import { Command, type CommandDefinition } from '../utils/command.js';
import type { CLIOptions, CommandResult, CommandContext, ProjectSnapshot } from '../types/index.js';
import { join, relative, basename, dirname } from 'path';
import { readFileSync, existsSync, lstatSync, readdirSync } from 'fs';
import ignore from 'ignore';
import { pack as repomixPack } from 'repomix';

export class PackCommand extends Command {
  readonly definition: CommandDefinition = {
    name: 'pack',
    description: 'Create a snapshot from a local directory',
    usage: 'jref pack [directory] [options]',
    examples: [
      'jref pack . > snapshot.json',
      'jref pack ./my-project --instruction "Follow these rules" > snapshot.json'
    ]
  };

  async execute(
    args: string[],
    options: CLIOptions,
    _context: CommandContext
  ): Promise<CommandResult> {
    try {
      const { flags, targetDir } = this.parseArgs(args);
      const rootDir = targetDir || process.cwd();

      if (!existsSync(rootDir)) {
        return this.error(`Directory not found: ${rootDir}`, options);
      }

      // Configure repomix to match jref's behavior
      const repomixConfig = {
        // Output format
        output: {
          style: 'json' as const,
          filePath: '-', // stdout equivalent
          // Don't include extra metadata that jref handles separately
          fileSummary: flags.summary !== undefined, // Only include if --summary flag used
          directoryStructure: true,
          files: true,
          // Don't include extra sections
          removeComments: false,
          removeEmptyLines: false,
          truncateBase64: false,
          showLineNumbers: false,
          copyToClipboard: false,
          includeEmptyDirectories: true,
          includeFullDirectoryStructure: true,
          splitOutput: undefined,
          tokenCountTree: false,
          headerText: undefined,
          instructionFilePath: undefined,
          // Git options - we'll handle .gitignore ourselves for consistency
          git: {
            sortByChanges: false,
            includeDiffs: false,
            includeLogs: false,
            includeLogsCount: 0
          }
        },
        // Input options
        input: {
          maxFileSize: 50 * 1024 * 1024 // 50MB default
        },
        // Ignore settings - we want to use .gitignore like jref does
        ignore: {
          useGitignore: true,
          useDotIgnore: true,
          useDefaultPatterns: true,
          customPatterns: []
        },
        // Security - disable for now to match jref's behavior
        security: {
          enableSecurityCheck: false
        },
        // Token counting - not needed for jref
        tokenCount: {
          encoding: 'o200k_base'
        }
      };

      // Run repomix
      const result = await repomixPack([rootDir], repomixConfig);

      // Extract the output from repomix result
      // repomix returns an object with outputFiles when using programmatic API
      let jsonOutput = '';
      if (result.outputFiles) {
        // When using programmatic API, outputFiles contains the generated content
        for (const file of result.outputFiles) {
          if (file.filePath.includes('repomix-output.json')) {
            jsonOutput = file.content;
            break;
          }
        }
      }

      // If we didn't get JSON output from repomix, try to get it from stdout
      // For now, let's assume we can get it from the result directly
      if (!jsonOutput && result.outputForMetrics) {
        // Try to reconstruct from the metrics output
        // This is a fallback - ideally we'd get the direct JSON output
      }

